var b="url",c="仓库配置.html",d="generationDate",e=new Date(1781494385813.96),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="f458912a721d477ba72eb7ef83052294",v="type",w="Axure:Page",x="仓库配置",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="60f229bfcae54fb69f94deb4d88b8399",E="label",F="参与类型",G="说明",H="<p><span>参与类型可选项：</span></p><p><span>1.直接入库(初始化选中) 2.采购入库(初始化选中) 3.退料入库(初始化未选中)</span></p>",I="2",J="7c5e1a1b506b41acade29523459c66c0",K="权重范围",L="<p><span>1.参与类型可选项：</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.全部(初始化选中)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.按天</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; c.按量</span></p><p><span>2.按天：展示编辑域 近X天；格式为正整数</span></p><p><span>3.按量：展示编辑域 近X单位量；格式为正整数</span></p>",M="3",N="f688b25ea8414f038b8e982ef8d1e391",O="4",P="e5efc992a6534139b5d39f544e627eed",Q="锁库自动释放：",R="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#02A7F0;\">自动释放应用 </span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">: 新增锁库单至[物料锁定]时，根据创建日期及当前填写的天数定义对应的“自动释放时间”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; eg.定时任务在到达“自动释放时间”时，将 '状态==使用中' 且 '当前勾选∈锁定类型' 的锁库订单进行变更</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a.“状态”变更为'已释放'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b.“更新人”记录作'系统释放'</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; c.“更新时间”记录为自动释放时间</span></p>",S="5",T="117521e20cd7489599a9450532d8e0ea",U="超期天数",V="<p><span>1.格式：正整数(大于0)</span></p><p><span>2.右侧Tooltips：以“创建时间”为准，超过将自动释放</span></p>",W="6",X="8da4b4ac5c654037b541d3c63baa1d44",Y="支持结算类型：",Z="<p><span>对应选项(全部[物料库存日志]中的单据类型)：</span></p><p><span>1.直接入库</span></p><p><span>2.采购入库</span></p><p><span>3.退料入库</span></p><p><span>4.加工入库</span></p><p><span>5.直接出库</span></p><p><span>6.采退出库</span></p><p><span>7.领料出库</span></p><p><span>8.加工出库</span></p><p><span>9.直接调整</span></p><p><span>10.直接调拨</span></p>",ba="7",bb="f36aaddde373444b966adb55300322ec",bc="自动汇总：",bd="<p><span>1.选中</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.将'缸号'和'批次号'同步选中</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.将'缸号'和'批次号'选项启用</span></p><p><span>2.取消选中</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.将'缸号'和'批次号'同步取消选中</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.将'缸号'和'批次号'选项禁用</span></p>",be="8",bf="23f75e94f8eb4cd7b20a3bb297982eae",bg="参考单价取值：",bh="<p><span>可选项：</span></p><p><span>1.加权平均</span></p><p><span>2.最新单价</span></p><p><span>3.物料默认</span></p>",bi="9",bj="9731a6739b9349da9a2a724a3b8e3b09",bk="出库未指定唯一码：",bl="<p><span>系统配置：出库未指定库存扣除方式，作用于出库单</span></p><p><span>1.旧库存优先(初始化选中)：账龄数值大</span></p><p><span>2.新库存优先：账龄数值小</span></p><p><span>3.小库存优先：可用库存数值小</span></p><p><span>4.大库存优先：可用库存数值大</span></p>",bm="10",bn="6ca5982a9bf04bd8937fb80b28bdc39d",bo="调拨未指定唯一码：",bp="<p><span>1.旧库存优先(初始化选中)：账龄数值大</span></p><p><span>2.新库存优先：账龄数值小</span></p><p><span>3.小库存优先：可用库存数值小</span></p><p><span>4.大库存优先：可用库存数值大</span></p>",bq="11",br="12443b66191f44d5b1cdb181783794a9",bs="调整依据字段：",bt="<p><span>系统配置：调整未指定库存扣除方式，作用于调整单</span></p><p><span><br></span></p><p><span style=\"color:#D9001B;\">选中字段决定了调整单保存后下次编辑或审核时根据实际库存与选中计算计算另一字段值</span></p><p><span><br></span></p><p><span>附：由于在调整单未提交至审核的过程中，实际库存可能产生变更，库存的调整的补充或扣减需要有依据字段</span></p>",bu="12",bv="ed7b72ab0d104e368b1ce00a01ea31aa",bw="调整未指定唯一码：",bx="<p><span>系统配置：调整未指定库存扣除方式，作用于调整单</span></p><p><span><br></span></p><p><span>1.旧库存优先(初始化选中)：账龄数值大</span></p><p><span>2.新库存优先：账龄数值小</span></p><p><span>3.小库存优先：可用库存数值小</span></p><p><span>4.大库存优先：可用库存数值大</span></p>",by="13",bz="923a02162d344548a1297d5407483e03",bA="小程序默认单价",bB="<p><span>1.用于小程序进行出入库确认时生成对应单据[出/入库物料汇总]中的&quot;单价&quot;，及对&quot;总金额&quot;的计算</span></p><p><span><br></span></p><p><span>2.加权平均</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.找到单个物料SKU在[物料库存日志-汇总日志]中“关联单据”属于选中</span><span style=\"text-decoration:underline ;\">参与类型</span><span>的数据</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"color:#D9001B;\">加权平均=对应数据的 Σ(数量*单价)/Σ数量</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.</span><span style=\"text-decoration:underline ;\">全部</span><span>：使用全部数据的 “数量”、“单价”进行计算</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; d.</span><span style=\"text-decoration:underline ;\">按天</span><span>：仅使用[汇总日志]中&quot;操作时间&quot;与当前日期的间隔不超过</span><span style=\"text-decoration:underline ;\">范围天数</span><span>的数据进行计算</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; e.</span><span style=\"text-decoration:underline ;\">按量</span><span>：仅使用[汇总日志]中按&quot;操作时间&quot;倒叙取数据行中的'数量&quot;，累计数量不超过</span><span style=\"text-decoration:underline ;\">范围单位量</span><span>的数据进行计算</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.若权重范围设置的值为近200单位量，查询到最新的两条相关数据为①单价A 180单位量 ②单价B 150单位量</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.最终取 单价A 180单位量 和 单价B 20单位量</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.加权平均=(180*A+20*B)/200</span></p><p><span><br></span></p><p><span>3.最新单价：找到单个物料SKU在[物料库存日志-汇总日志]中“关联单据”属于选中</span><span style=\"text-decoration:underline ;\">参与类型</span><span>的&quot;操作时间&quot;最新的数据的 </span><span style=\"color:#D9001B;\">单价</span></p><p><span><br></span></p><p><span>4.默认为0：直接记为'0'</span></p><p><span><br></span></p><p><span>5.物料默认：物料编码对应在[基础数据&gt;&gt;物料管理]中的“默认单价”；为空时视为'0'</span></p>",bC="14",bD="4cc97753e3b34286925e9d2f6f52d1ff",bE="保存",bF="<p><span>1.若</span><span style=\"text-decoration:underline ;\">通用设置</span><span>下</span><span style=\"color:#0000FF;\">[加权计算公式&gt;&gt;权重范围]=='按天'</span><span>，校验数值为正整数；否则Toast提示：请填写正确的权重范围天数</span></p><p><span>2.若</span><span style=\"text-decoration:underline ;\">通用设置</span><span>下</span><span style=\"color:#0000FF;\">[加权计算公式&gt;&gt;权重范围]=='按量'</span><span>，校验数值为正整数；否则Toast提示：请填写正确的权重范围单位量</span></p><p><span>3.若</span><span style=\"text-decoration:underline ;\">通用设置</span><span>下</span><span style=\"color:#0000FF;\">[锁库自动释放]中</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">存在选中</span><span>时，校验“超期天数”数值为正整数；否则Toast提示：请填写锁库自动释放超期天数</span></p><p><span>4.若</span><span style=\"text-decoration:underline ;\">入库单</span><span>下</span><span style=\"color:#0000FF;\">[自动汇总]</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">选中</span><span>时，判断下属勾选项中是否</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">存在选中项</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.存在选中项：不做处理</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.不存在选中项：将[自动汇总]取消选中</span></p>",bG="style",bH="baseStyle",bI="627587b6038d43cca051c114ac41ad32",bJ="pageAlignment",bK="center",bL="fill",bM="fillType",bN="solid",bO="color",bP=0xFFFFFFFF,bQ="image",bR="imageAlignment",bS="near",bT="imageRepeat",bU="auto",bV="favicon",bW="sketchFactor",bX="0",bY="colorStyle",bZ="appliedColor",ca="fontName",cb="Applied Font",cc="borderWidth",cd="borderVisibility",ce="borderFill",cf=0xFF797979,cg="cornerRadius",ch="cornerVisibility",ci="outerShadow",cj="on",ck=false,cl="offsetX",cm=5,cn="offsetY",co="blurRadius",cp="spread",cq="r",cr=0,cs="g",ct="b",cu="a",cv=0.349019607843137,cw="adaptiveStyles",cx="interactionMap",cy="diagram",cz="objects",cA="id",cB="84e9711a550c415e86132248cd9564b8",cC="friendlyType",cD="顶部-1600",cE="referenceDiagramObject",cF="styleType",cG="visible",cH=true,cI=1600,cJ=890,cK="imageOverrides",cL="masterId",cM="17274bcf1e104e0881fe339074a81b64",cN="449272d563274f4c8e857c65446fee30",cO="动态面板",cP="dynamicPanel",cQ=1530,cR=688,cS="location",cT="x",cU=70